 {"id":"bd-2eo1l","title":"Subtask: Unit Tests for --robot-smart-restart Command","description":"## Subtask: Unit Tests for --robot-smart-restart Command

### Purpose
Comprehensive unit tests for the smart-restart command, focusing on the CRITICAL safety logic that prevents interrupting working agents.

### Test File
`internal/robot/smartrestart_test.go`

### Test Coverage

```go
package robot

import (
    "testing"
)

// CRITICAL TEST: Working agent MUST NOT be restarted
func TestSmartRestart_WorkingAgent_Refused(t *testing.T) {
    mockState := PaneWorkStatus{
        IsWorking:      true,
        Recommendation: "DO_NOT_INTERRUPT",
        Confidence:     0.95,
    }

    action := decideRestart(mockState, false) // force=false

    if action.Action != "SKIPPED" {
        t.Fatalf("CRITICAL: Working agent was NOT protected! Action=%s", action.Action)
    }
    if !strings.Contains(action.Reason, "working") {
        t.Errorf("Reason should mention agent is working: %s", action.Reason)
    }
}

func TestSmartRestart_IdleAgent_Restarted(t *testing.T) {
    mockState := PaneWorkStatus{
        IsIdle:         true,
        IsWorking:      false,
        Recommendation: "SAFE_TO_RESTART",
    }

    action := decideRestart(mockState, false)

    if action.Action != "RESTART" {
        t.Errorf("Idle agent should be restarted, got %s", action.Action)
    }
}

func TestSmartRestart_RateLimited_Wait(t *testing.T) {
    mockState := PaneWorkStatus{
        IsRateLimited:  true,
        Recommendation: "RATE_LIMITED_WAIT",
    }

    action := decideRestart(mockState, false)

    if action.Action != "WAITING" {
        t.Errorf("Rate limited agent should wait, got %s", action.Action)
    }
}

func TestSmartRestart_ForceFlag_OverridesProtection(t *testing.T) {
    mockState := PaneWorkStatus{
        IsWorking:      true,
        Recommendation: "DO_NOT_INTERRUPT",
    }

    action := decideRestart(mockState, true) // force=true

    if action.Action != "RESTART" {
        t.Errorf("Force flag should override protection, got %s", action.Action)
    }
    if !strings.Contains(action.Reason, "forced") {
        t.Errorf("Reason should mention force: %s", action.Reason)
    }
}

func TestSmartRestart_DryRun_NoAction(t *testing.T) {
    opts := SmartRestartOptions{
        DryRun: true,
        Force:  false,
    }

    result, err := testSmartRestart("test_session", []int{2}, opts, PaneWorkStatus{
        IsIdle: true,
    })

    if err != nil {
        t.Fatalf("Dry run failed: %v", err)
    }

    action := result.Actions["2"]
    if action.Action != "WOULD_RESTART" {
        t.Errorf("Dry run should show WOULD_RESTART, got %s", action.Action)
    }
}

func TestSmartRestart_LowContext_IdleAgent(t *testing.T) {
    ctx := 12.0
    mockState := PaneWorkStatus{
        IsIdle:           true,
        IsContextLow:     true,
        ContextRemaining: &ctx,
        Recommendation:   "SAFE_TO_RESTART",
    }

    action := decideRestart(mockState, false)

    if action.Action != "RESTART" {
        t.Errorf("Low context idle agent should restart, got %s", action.Action)
    }
    if !strings.Contains(action.Reason, "context") {
        t.Errorf("Reason should mention low context: %s", action.Reason)
    }
}

func TestSmartRestart_LowContext_WorkingAgent(t *testing.T) {
    ctx := 12.0
    mockState := PaneWorkStatus{
        IsWorking:        true, // Still working!
        IsContextLow:     true,
        ContextRemaining: &ctx,
        Recommendation:   "CONTEXT_LOW_CONTINUE",
    }

    action := decideRestart(mockState, false)

    // MUST NOT restart working agent even with low context
    if action.Action != "SKIPPED" {
        t.Fatalf("CRITICAL: Working agent with low context was interrupted! Action=%s", action.Action)
    }
}

func TestSmartRestart_UnknownState_Safe(t *testing.T) {
    mockState := PaneWorkStatus{
        Recommendation: "UNKNOWN",
        Confidence:     0.3,
    }

    action := decideRestart(mockState, false)

    // Unknown state should NOT restart (conservative)
    if action.Action == "RESTART" {
        t.Error("Unknown state should not trigger restart (conservative)")
    }
}

func TestSmartRestart_ExitSequence_ClaudeCode(t *testing.T) {
    seq := getExitSequence("cc")

    if seq.Method != "double_ctrl_c" {
        t.Errorf("Claude Code should use double_ctrl_c, got %s", seq.Method)
    }
    if seq.DelayBetween.Milliseconds() < 50 || seq.DelayBetween.Milliseconds() > 200 {
        t.Errorf("Delay between Ctrl+C should be 50-200ms, got %v", seq.DelayBetween)
    }
}

func TestSmartRestart_ExitSequence_Codex(t *testing.T) {
    seq := getExitSequence("cod")

    if seq.Method != "exit_command" {
        t.Errorf("Codex should use /exit command, got %s", seq.Method)
    }
}

func TestSmartRestart_MultiplePanes_Summary(t *testing.T) {
    result := &SmartRestartResult{
        Actions: map[string]RestartAction{
            "2": {Action: "SKIPPED"},
            "3": {Action: "RESTARTED"},
            "4": {Action: "WAITING"},
        },
    }

    summary := buildRestartSummary(result.Actions)

    if summary.Restarted != 1 {
        t.Errorf("Expected 1 restarted, got %d", summary.Restarted)
    }
    if summary.Skipped != 1 {
        t.Errorf("Expected 1 skipped, got %d", summary.Skipped)
    }
    if summary.Waiting != 1 {
        t.Errorf("Expected 1 waiting, got %d", summary.Waiting)
    }
}

func TestSmartRestart_PostState_Verification(t *testing.T) {
    // After restart, we should verify the new agent launched
    postState := &PostStateInfo{
        AgentRunning: true,
        AgentType:    "cod",
    }

    if !postState.AgentRunning {
        t.Error("Post-restart should confirm agent is running")
    }
}

func TestSmartRestart_FailedRestart_Logged(t *testing.T) {
    // Simulate restart failure
    action := RestartAction{
        Action: "FAILED",
        Reason: "Eligible for restart",
        Error:  "tmux pane not found",
    }

    if action.Error == "" {
        t.Error("Failed restart should include error message")
    }
}

// Test helper
func testSmartRestart(session string, panes []int, opts SmartRestartOptions, mockState PaneWorkStatus) (*SmartRestartResult, error) {
    // Mock the IsWorking call
    originalIsWorking := isWorkingFunc
    isWorkingFunc = func(s string, p []int, v bool) (*IsWorkingResult, error) {
        result := &IsWorkingResult{Panes: make(map[string]PaneWorkStatus)}
        for _, pane := range p {
            result.Panes[strconv.Itoa(pane)] = mockState
        }
        return result, nil
    }
    defer func() { isWorkingFunc = originalIsWorking }()

    return SmartRestart(session, panes, opts)
}
```

### Decision Matrix Tests

```go
func TestDecisionMatrix(t *testing.T) {
    tests := []struct {
        name           string
        isWorking      bool
        isIdle         bool
        isRateLimited  bool
        isContextLow   bool
        force          bool
        expectedAction string
    }{
        {"Working, no force", true, false, false, false, false, "SKIPPED"},
        {"Working, force", true, false, false, false, true, "RESTART"},
        {"Idle", false, true, false, false, false, "RESTART"},
        {"Rate limited", false, false, true, false, false, "WAITING"},
        {"Idle + low context", false, true, false, true, false, "RESTART"},
        {"Working + low context", true, false, false, true, false, "SKIPPED"},
        {"Working + rate limited", true, false, true, false, false, "SKIPPED"},
    }

    for _, tt := range tests {
        t.Run(tt.name, func(t *testing.T) {
            state := PaneWorkStatus{
                IsWorking:     tt.isWorking,
                IsIdle:        tt.isIdle,
                IsRateLimited: tt.isRateLimited,
                IsContextLow:  tt.isContextLow,
            }

            action := decideRestart(state, tt.force)

            if action.Action != tt.expectedAction {
                t.Errorf("Expected %s, got %s", tt.expectedAction, action.Action)
            }
        })
    }
}
```

